import React, { useState } from "react";
import Navbar from "../components/Navbar";
import axios from "axios";

function UploadScan() {

  const [file, setFile] = useState(null);
  const [original, setOriginal] = useState(null);
  const [mask, setMask] = useState(null);
  const [highlight, setHighlight] = useState(null);

  const handleUpload = async () => {

    const formData = new FormData();
    formData.append("file", file);

    const response = await axios.post(
      "http://localhost:5000/predict",
      formData
    );

    setOriginal("data:image/png;base64," + response.data.original);
    setMask("data:image/png;base64," + response.data.mask);
    setHighlight("data:image/png;base64," + response.data.highlight);
  };

  return (
    <>
      <Navbar />

      <div className="container mt-5">

        <h2 className="mb-4">Upload MRI Scan</h2>

        <input
          type="file"
          className="form-control mb-3"
          onChange={(e) => setFile(e.target.files[0])}
        />

        <button
          className="btn btn-primary"
          onClick={handleUpload}
        >
          Predict
        </button>

        <div className="row mt-5">

          {original && (
            <div className="col-md-4 text-center">
              <h5>Uploaded MRI</h5>
              <img src={original} alt="original" width="220"/>
            </div>
          )}

          {mask && (
            <div className="col-md-4 text-center">
              <h5>Tumor Mask</h5>
              <img src={mask} alt="mask" width="220"/>
            </div>
          )}

          {highlight && (
            <div className="col-md-4 text-center">
              <h5>Tumor Highlight</h5>
              <img src={highlight} alt="highlight" width="220"/>
            </div>
          )}

        </div>

      </div>
    </>
  );
}

export default UploadScan;
